sys_script_include.script:
var CareerScoreCalculator = Class.create();

CareerScoreCalculator.prototype = {

    initialize: function() {
    },

    calculate: function(profileSysId) {
		gs.info('CareerScoreCalculator started');

        var profileGR = new GlideRecord(
            'x_1920001_careeros_career_profile'
        );

        if (!profileGR.get(profileSysId))
            return;

        if (gs.nil(profileGR.target_role))
            return;

        var totalWeight = 0;
        var achievedWeight = 0;

        var roleSkills = {};

        var rs = new GlideRecord(
            'x_1920001_careeros_role_skill'
        );

        rs.addQuery('role', profileGR.target_role.toString());
        rs.query();

        while (rs.next()) {

            var skillId = rs.skills.toString();
            var weight = parseInt(rs.weight, 10);

            roleSkills[skillId] = weight;

            totalWeight += weight;
        }

        var ps = new GlideRecord(
            'x_1920001_careeros_profile_skill'
        );

        ps.addQuery('profile', profileSysId);
        ps.query();

        while (ps.next()) {

            var skillId = ps.skill.toString();

            if (roleSkills[skillId]) {

                achievedWeight += roleSkills[skillId];
            }
        }

        var score = 0;

        if (totalWeight > 0) {

            score = Math.round(
                (achievedWeight / totalWeight) * 100
            );
        }

        profileGR.setWorkflow(false);

        profileGR.career_score = score;

        profileGR.update();

        gs.info(
            'CareerOS Score for profile ' +
            profileGR.full_name +
            ' = ' +
            score
        );
    },

    type: 'CareerScoreCalculator'
};
